hooks.onDraw:
const s = world.state;
const A = function (v) { return Math.max(0, Math.min(1, v || 0)); };
const PJS = ' "Plus Jakarta Sans", ui-sans-serif, system-ui';
const ls = world.entities.filter(function (e) { return e.type === 'learner'; });
ls.sort(function (a, b) { return (a.y || 0) - (b.y || 0); });
for (const e of ls) world.draw.learner(e);
const cx = 450, cy = 240, R = 115, o = 71;
const C = { x: cx, y: cy - o }, P = { x: cx - 61.5, y: cy + 35.5 }, T = { x: cx + 61.5, y: cy + 35.5 };
const amber = '#F4AC1D', green = '#4f8a5e', blue = '#5b8def';
const circ = function (c, col, a) {
  if (a < 0.01) return;
  ctx.save();
  ctx.globalAlpha = a * 0.26;
  ctx.fillStyle = col;
  ctx.beginPath(); ctx.arc(c.x, c.y, R, 0, Math.PI * 2); ctx.fill();
  ctx.globalAlpha = Math.min(1, a * 0.95);
  ctx.lineWidth = 2.4; ctx.strokeStyle = col;
  ctx.beginPath(); ctx.arc(c.x, c.y, R, 0, Math.PI * 2); ctx.stroke();
  ctx.restore();
};
const chip = function (x, y, txt, a, big) {
  if (a < 0.01) return;
  ctx.save();
  ctx.globalAlpha = a;
  ctx.font = (big ? '700 15px' : '700 12px') + PJS;
  ctx.textAlign = 'center'; ctx.textBaseline = 'middle';
  const w = ctx.measureText(txt).width + (big ? 24 : 14), h = big ? 26 : 19;
  world.draw.rrect(x - w / 2, y - h / 2, w, h, h / 2);
  ctx.fillStyle = big ? '#1F2547' : 'rgba(18,23,42,0.92)'; ctx.fill();
  world.draw.rrect(x - w / 2, y - h / 2, w, h, h / 2);
  ctx.lineWidth = 1; ctx.strokeStyle = big ? '#F4AC1D' : 'rgba(232,226,210,0.30)'; ctx.stroke();
  ctx.fillStyle = '#FBFAF6'; ctx.fillText(txt, x, y + 0.5);
  ctx.restore();
};
const tag = function (x, y, l1, l2, ax, ay, lx, ly, a) {
  if (a < 0.01) return;
  ctx.save(); ctx.globalAlpha = a;
  world.draw.arrow(ax, ay, lx, ly, { color: 'rgba(154,163,189,0.92)', width: 1.6, head: 7 });
  ctx.font = '600 12px' + PJS; ctx.textAlign = 'center'; ctx.textBaseline = 'middle';
  const w = Math.max(ctx.measureText(l1).width, ctx.measureText(l2).width) + 18, h = 36;
  world.draw.rrect(x - w / 2, y - h / 2, w, h, 8);
  ctx.fillStyle = 'rgba(18,23,42,0.94)'; ctx.fill();
  world.draw.rrect(x - w / 2, y - h / 2, w, h, 8);
  ctx.lineWidth = 1; ctx.strokeStyle = 'rgba(232,226,210,0.30)'; ctx.stroke();
  ctx.fillStyle = '#e8e2d2';
  ctx.fillText(l1, x, y - 8); ctx.fillText(l2, x, y + 8);
  ctx.restore();
};
if (A(s.core) > 0.01) {
  const aa = A(s.core);
  const g = ctx.createRadialGradient(cx, cy, 0, cx, cy, 82);
  g.addColorStop(0, 'rgba(244,172,29,' + (0.34 * aa).toFixed(2) + ')');
  g.addColorStop(1, 'rgba(244,172,29,0)');
  ctx.save(); ctx.fillStyle = g; ctx.beginPath(); ctx.arc(cx, cy, 82, 0, Math.PI * 2); ctx.fill(); ctx.restore();
}
if (A(s.ctx) > 0.01) {
  ctx.save();
  ctx.globalAlpha = A(s.ctx) * 0.9;
  ctx.setLineDash([6, 7]); ctx.lineWidth = 2; ctx.strokeStyle = 'rgba(154,163,189,0.85)';
  ctx.beginPath(); ctx.ellipse(cx, cy - 18, 208, 194, 0, 0, Math.PI * 2); ctx.stroke();
  ctx.setLineDash([]); ctx.restore();
  chip(cx, cy - 212, 'CONTEXTOS', A(s.ctx));
}
circ(C, amber, A(s.ck));
circ(P, green, A(s.pk));
circ(T, blue, A(s.tk));
tag(152, 176, 'Conocimiento Pedagógico', 'del Contenido', 236, 184, 388, 206, A(s.pck));
tag(748, 176, 'Conocimiento Tecnológico', 'del Contenido', 664, 184, 512, 206, A(s.tck));
tag(450, 442, 'Conocimiento Tecnológico', 'Pedagógico', 450, 424, 450, 328, A(s.tpk));
chip(cx, C.y - R * 0.52, 'CONTENIDO', A(s.ck));
chip(P.x - 52, P.y + R * 0.46, 'PEDAGOGÍA', A(s.pk));
chip(T.x + 52, T.y + R * 0.46, 'TECNOLOGÍA', A(s.tk));
chip(cx - 58, cy - 34, 'PCK', A(s.pck));
chip(cx + 58, cy - 34, 'TCK', A(s.tck));
chip(cx, cy + 68, 'TPK', A(s.tpk));
chip(cx, cy, 'TPACK', A(s.core), true);
